```

- Updates CSS variables so the entire site theme updates instantly.
- Saves selections in browser storage.

Dark mode:

```js
const enableDarkmode = () => { document.body.classList.add("darkmode"); localStorage.setItem("darkmode", "active"); };
const disableDarkmode = () => { document.body.classList.remove("darkmode"); localStorage.removeItem("darkmode"); };
const updateIcon = () => { themeSwitch.textContent = document.body.classList.contains("darkmode") ? "light_mode" : "dark_mode"; };

if (darkMode === "active") enableDarkmode();
