### 10. Typing Effect

```js
const words = ["Student", "Learner", "Developer"];
let i = 0;
let j = 0;
let currentWord = "";
let isDeleting = false;

function type() {
  currentWord = words[i];
  if (isDeleting) j--;
  else j++;
  document.getElementById("typing-text").textContent =
    currentWord.substring(0, j);
  if (!isDeleting && j === currentWord.length) {
    isDeleting = true;
    setTimeout(type, 1000);
    return;
  }
  if (isDeleting && j === 0) {
    isDeleting = false;
    i = (i + 1) % words.length;
  }
  setTimeout(type, isDeleting ? 50 : 100);
}
type();
```

- Cycles through words one letter at a time.
- Types a word, pauses, deletes it, then types the next word.
- Creates a dynamic hero headline.

---

### 11. Active Navigation Highlight

```js
let sections = document.querySelectorAll("section");
let navLinks = document.querySelectorAll(".navbar a");

window.addEventListener("scroll", () => {
  let top = window.scrollY;
  sections.forEach(sec => {
    let offset = sec.offsetTop - 150;
    let height = sec.offsetHeight;
    let id = sec.getAttribute("id");

    if (top >= offset && top < offset + height) {
      navLinks.forEach(link => { link.classList.remove("active"); });
      const activeLink = document.querySelector(".navbar a[href*=" + id + "]");
      if (activeLink) { activeLink.classList.add("active"); }
    }
  });
});
```

- Detects which section is currently visible.
- Sets the corresponding nav link to active.
- Helps users know where they are on the page.

---

### 12. Scroll to Top Button

```js
const scrollBtn = document.getElementById("scrollTopBtn");

window.addEventListener("scroll", () => {
  scrollBtn.style.display = window.scrollY > 300 ? "block" : "none";
});

scrollBtn.addEventListener("click", () => {
  window.scrollTo({ top: 0, behavior: "smooth" });
});
```

- Button appears after scrolling 300px.
- Click scrolls smoothly back to top.

---

### 13. Contact Form Validation and Submission

```js
const form = document.getElementById('form');
const result = document.getElementById('result');

form.addEventListener('submit', function(e) {
  e.preventDefault();
  const name = form.querySelector('[name="Fullname"]').value.trim();
  const email = form.querySelector('[name="Email"]').value.trim();
  const message = form.querySelector('[name="message"]').value.trim();

  if (!name || !email || !message) {
    result.innerHTML = "Please fill in all fields.";
    result.style.display = "block";
    return;
  }

  const formData = new FormData(form);
  const object = Object.fromEntries(formData);
  const json = JSON.stringify(object);
  result.innerHTML = "Please wait..."
  result.style.display = "block";

  fetch('https://api.web3forms.com/submit', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
    body: json
  })
  .then(async (response) => {
    let json = await response.json();
    if (response.status == 200) {
      alert("Form submission successful!");
      result.innerHTML = json.message;
    } else {
      result.innerHTML = json.message;
    }
  })
  .catch(error => {
    result.innerHTML = "Something went wrong!";
  })
  .then(function() {
    form.reset();
    setTimeout(() => { result.style.display = "none"; }, 3000);
  });
});
```

- Prevents the default form submission so custom logic can run.
- Validates that required fields are not empty.
- Sends the form to Web3Forms as JSON.
- Shows success or error messages.
- Resets the form afterward.

