### 7. Counter Animation

Function:

```js
function animateCounter(element, target, duration = 2000) {
  let current = 0;
  const increment = target / (duration / 16);
  const counter = setInterval(() => {
    current += increment;
    if (current >= target) {
      element.textContent = target + '+';
      clearInterval(counter);
    } else {
      element.textContent = Math.floor(current) + '+';
    }
  }, 16);
}
```

- Slowly increments number from 0 to target.
- Uses ~60 frames per second style timing.
- Displays a `+` sign after the number.

Observer:

```js
const counterObserver = new IntersectionObserver((entries) => {
  entries.forEach((entry) => {
    if (entry.isIntersecting && !entry.target.dataset.counted) {
      entry.target.dataset.counted = 'true';
      const countValue = parseInt(entry.target.dataset.count) || 5;
      animateCounter(entry.target, countValue);
    }
  });
});

document.querySelectorAll('.counter').forEach((el) => {
  counterObserver.observe(el);
});
```

- Starts the count animation when each counter scrolls into view.
- Ensures it only runs once.

